VALUES
  ('retired-d0d1b9a2-moex-00400', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依據審計準則公報第七十二號「查核財務報表對法令遵循之考量」，查核人員如認為受查者管理 階層或治理單位成員疑似涉及未遵循法令事項，下列何者並非查核人員可採取之行動？', '["與受查者適當管理階層或治理單位溝通", "考量是否取得法律專家之意見", "依法向適當之政府權責機關報告", "對該疑似未遵循法令事項提供合理確信"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00401', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '集團主辦會計師如認為集團查核團隊因受集團管理階層之限制，而無法透過集團查核團隊之工作 或採用組成個體查核人員之工作取得足夠及適切之查核證據，致無法對集團財務報表表示意見 時，下列何者為集團主辦會計師正確之因應？', '["於承接新案件之情況下，接受中度確信服務之委任", "於續任案件之情況下，繼續接受委任", "如終止該委任係不可能，則應於可能之範圍內對集團財務報表執行查核，並對集團財務報表出 具無法表示意見之查核報告", "如法令禁止查核人員拒絕接受委任，則應於可能之範圍內對集團財務報表執行查核，並將相關 發現納入集團財務報表查核報告之關鍵查核事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00402', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依我國審計準則公報第五十三號「查核證據」之規範，當外部受查詢者未具備相關知識或管理階 層專家缺乏客觀性時，取自外部獨立來源之資訊可能不具可靠性。雖然例外情況有可能存在，但 查核證據之可靠性仍可歸納出原則。下列敘述何者錯誤？', '["當查核證據取自受查者外部獨立來源時，其可靠性較高", "書面會議紀錄較會後討論事項之口頭聲明更為可靠", "查核人員查詢有關控制之執行情形所取得的查核證據，較觀察控制之執行情形所取得的查核證 據更為可靠", "當查核證據來自受查者內部時，若受查者相關控制（包括對其編製及維護之控制）有效，其可 靠性較高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00403', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依我國審計準則公報第五十六號「會計估計與相關揭露之查核」之規範，查核人員於查核財務報 表時，對會計估計（包括公允價值會計估計）與相關揭露負有責任。下列敘述何者錯誤？', '["查核人員應判斷是否有會計估計因具高度不確定性而存有顯著風險", "會計估計之重大不實表達風險，亦受非故意或故意之管理階層偏頗之影響", "所有須按公允價值衡量之財務報表項目，通常易受衡量日後事件或狀況所影響，故均涉及估計 不確定性", "若管理階層將作為會計估計之基礎，由依市價評估改為依模型評估，查核人員應依經濟情況評 估管理階層對市場之假設是否合理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00404', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', 'A公司決定財務報表查核簽證會計師自甲會計師更換為乙會計師，依審計準則公報規定，下列敘 述何者錯誤？', '["A 公司與乙會計師簽署委任書後，乙會計師應立即去函甲會計師查詢有關 A 公司管理階層品 德、甲會計師與A公司管理階層對會計原則與查核程序是否存歧見，以及A公司更換會計師 之理由", "乙會計師應執行程序以評估與A公司就查核財務報表而言是否具獨立性，如未具獨立性或無法 採取其他措施以降低獨立性之影響，於此情況下，乙會計師應不得接受委任", "乙會計師應藉由委任書之簽署以確認A公司管理階層已認知其對財務報表編製之相關責任", "乙會計師於受任後應對期初餘額執行查核程序，以確認期初餘額是否存有影響本期財務報表之 不實表達，以及前期所適用之會計政策是否適當，且於本期一致適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00405', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列何者非內部控制組成要素「控制環境」之要素？', '["企業管理階層重視專業能力並適才適所", "治理單位定期與外部查核人員及內部稽核職能溝通其應監督之事項", "劃分營運活動權責與建立報告關係及授權層級", "建立企業營運風險評估流程，並選擇因應風險之控制作業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00406', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依據審計準則公報第四十八號之規定，有關重大不實表達風險之辨認與評估，下列敘述何者錯 誤？', '["重大不實表達風險可分整體財務報表層級與個別項目聲明層級", "整體財務報表之重大不實表達風險特別可能與導因於不良的控制環境有關", "查核人員於判斷所辨認之風險是否為顯著風險時，應考慮與該項風險有關之控制所能降低風險 之效果", "某些交易類別或科目餘額係透過高度自動化加以處理，而極少人工介入，僅經由證實程序可能 無法取得足夠及適切查核證據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00407', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依據審計準則規定，下列何種控制可能使查核人員無法信賴以前年度內部控制執行有效性之查核', '["擬仰賴之控制與顯著風險相關", "擬仰賴之控制，其執行控制之人員異動，但控制程序 及系統與以前年度並無改變", "擬仰賴之控制已超過2年未進行測試", "擬仰賴之控制於上年度 被查核人員辨認為顯著缺失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00408', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '於查核受查者應收帳款之預期信用損失時，查核人員認為管理階層所使用之會計估計不合理，該 預期信用損失金額與查核人員所評估金額之差異，係屬：', '["實際不實表達", "判斷性不實表達", "推估不實表達", "預期不實表達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00409', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列何者為最無法查出是否存有或有負債的查核程序？', '["檢查客戶函證之回函內容", "銀行函證之回函內容", "檢查專業服務之發票內容", "閱讀董事會會議紀錄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
